inline bool VerifyAnyPayload(flatbuffers::Verifier &verifier, const void *obj, AnyPayload type) {
  switch (type) {
    case AnyPayload_NONE: {
      return true;
    }
    case AnyPayload_HelloMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::HelloMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_ClientMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::ClientMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_ServerMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::ServerMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_RequestRoomHistoryPayload: {
      auto ptr = reinterpret_cast<const ChatApp::RequestRoomHistoryPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_RequestMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::RequestMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_PullMissingMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::PullMissingMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_MessageAckPayload: {
      auto ptr = reinterpret_cast<const ChatApp::MessageAckPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_BatchPullMessagePayload: {
      auto ptr = reinterpret_cast<const ChatApp::BatchPullMessagePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_JoinSessionPayload: {
      auto ptr = reinterpret_cast<const ChatApp::JoinSessionPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_SignalingFromClientPayload: {
      auto ptr = reinterpret_cast<const ChatApp::SignalingFromClientPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_SignalingFromServerPayload: {
      auto ptr = reinterpret_cast<const ChatApp::SignalingFromServerPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case AnyPayload_SignalingFromClientJoinPayload: {
      auto ptr = reinterpret_cast<const ChatApp::SignalingFromClientJoinPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyAnyPayloadVector(flatbuffers::Verifier &verifier, const flatbuffers::Vector<flatbuffers::Offset<void>> *values, const flatbuffers::Vector<uint8_t> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyAnyPayload(
        verifier,  values->Get(i), types->GetEnum<AnyPayload>(i))) {
      return false;
    }
  }
  return true;
}

inline const ChatApp::RootMessage *GetRootMessage(const void *buf) {
  return flatbuffers::GetRoot<ChatApp::RootMessage>(buf);
}

inline const ChatApp::RootMessage *GetSizePrefixedRootMessage(const void *buf) {
  return flatbuffers::GetSizePrefixedRoot<ChatApp::RootMessage>(buf);
}

inline bool VerifyRootMessageBuffer(
    flatbuffers::Verifier &verifier) {
  return verifier.VerifyBuffer<ChatApp::RootMessage>(nullptr);
}

inline bool VerifySizePrefixedRootMessageBuffer(
    flatbuffers::Verifier &verifier) {
  return verifier.VerifySizePrefixedBuffer<ChatApp::RootMessage>(nullptr);
}

inline void FinishRootMessageBuffer(
    flatbuffers::FlatBufferBuilder &fbb,
    flatbuffers::Offset<ChatApp::RootMessage> root) {
  fbb.Finish(root);
}

inline void FinishSizePrefixedRootMessageBuffer(
    flatbuffers::FlatBufferBuilder &fbb,
    flatbuffers::Offset<ChatApp::RootMessage> root) {
  fbb.FinishSizePrefixed(root);
}

